sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?county (STR(?countyLabel) AS ?countyName)
WHERE {
  gokg:TaylorCountyFL goo:neighboringCounties ?county .
  ?county a goo:County ;
          rdfs:label ?countyLabel ;
          goo:locatedInState gokg:FloridaState .
  FILTER (LANGMATCHES(LANG(?countyLabel), "en"))
  {
    SELECT ?county (MAX(?sviYear) AS ?latestSviYear)
    WHERE {
      ?candidateSvi a goo:SVIRecord ;
                    goo:representsCounty ?county ;
                    goo:sviYear ?sviYear .
    }
    GROUP BY ?county
  }
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?county ;
             goo:sviYear ?latestSviYear ;
             goo:sviOverallScore ?sviScore .
  ?record a goo:CustomerOutageRecord ;
          goo:representsCounty ?county ;
          goo:recordDateTime ?recordDate ;
          goo:numberOfOutages ?numOutages .
  FILTER (?sviScore >= 0.5)
  FILTER (?numOutages > 10000)
  FILTER (?recordDate >= "2024-09-26T00:00:00Z"^^xsd:dateTime && ?recordDate < "2024-10-01T00:00:00Z"^^xsd:dateTime)
}
ORDER BY ?countyName
